import json
from langgraph.checkpoint.memory import MemorySaver
from vex import verify_schema

checkpointer = MemorySaver()

@vex.guardrail(name="state-schema")
def validate_checkpoint_schema(state: dict) -> dict:
    schema = {
        "type": "object",
        "properties": {
            "tenant_id": {"type": "string"},
            "pii_fields": {"type": "array"},
            "approval_status": {"enum": ["pending", "approved", "rejected"]}
        },
        "required": ["tenant_id"]
    }
    verify_schema(state, schema)
    return state

# Safe invocation with schema protection
result = app.invoke(
    input,
    config={"configurable": {"thread_id": "tenant_123", "checkpoint_schema": validate_checkpoint_schema}}
